1	// ──────────────────────────────────────────────────────────────────
2	// Today page fragments — CARs card, hero routine, completed, upcoming
3	// ──────────────────────────────────────────────────────────────────
4	
5	import type { Routine, QueueItemRow } from "../types";
6	import type { UpcomingItem } from "../domain/reflow";
7	import type { HevyWorkoutExercise, ActualSet } from "../domain/workout-compare";
8	import { escapeHtml, escapeAttr, truncate } from "../utils/html";
9	
10	/**
11	 * Daily CARs card — always shown at the top of Today.
12	 * Green accent label, exercise count, Push to Hevy + Details.
13	 */
14	export function carsCard(routine: Routine, hevyRoutineId?: string): string {
15	  const count = routine.exercises.length;
16	  const subtitle = routine.subtitle ?? `${count} exercises`;
17	
18	  const hevyButton = hevyRoutineId
19	    ? `<a href="https://hevy.com/routine/${escapeAttr(hevyRoutineId)}" target="_blank" class="btn btn-blue">Open in Hevy</a>`
20	    : `<button class="btn btn-blue" data-on:click="@post('/api/push-hevy/${escapeAttr(routine.id)}')">Push to Hevy</button>`;
21	
22	  const labelColor = escapeAttr(routine.color ?? "var(--green)");
23	  const label = escapeHtml(routine.isDaily ? "Daily" : routine.title);
24	
25	  return `<div class="card">
26	  <div class="card-label" style="color: ${labelColor}">${label}</div>
27	  <div class="card-title">${escapeHtml(routine.title)}</div>
28	  <div class="card-subtitle">${escapeHtml(subtitle)}</div>
29	  <div style="display:flex; gap:8px; margin-top:14px">
30	    ${hevyButton}
31	    <a href="/routine/${encodeURIComponent(routine.id)}" class="btn btn-ghost">Details</a>
32	  </div>
33	</div>`;
34	}
35	
36	/**
37	 * Hero routine card — the next main routine from the queue.
38	 * Blue accent label, description preview, Push to Hevy + Details.
39	 */
40	export function heroRoutineCard(routine: Routine, queueItem: QueueItemRow): string {
41	  const count = routine.exercises.length;
42	  const subtitle = routine.subtitle ?? `${count} exercises`;
43	  const desc = routine.description
44	    ? `<div class="card-desc">${escapeHtml(truncate(routine.description, 120))}</div>`
45	    : "";
46	
47	  const hevyButton = queueItem.hevy_routine_id
48	    ? `<a href="https://hevy.com/routine/${escapeAttr(queueItem.hevy_routine_id)}" target="_blank" class="btn btn-blue">Open in Hevy</a>`
49	    : `<button class="btn btn-blue" data-on:click="@post('/api/push-hevy/${escapeAttr(queueItem.routine_id)}')">Push to Hevy</button>`;
50	
51	  return `<div class="card">
52	  <div class="card-label" style="color: var(--blue)">Next Session</div>
53	  <div class="card-title">${escapeHtml(routine.title)}</div>
54	  <div class="card-subtitle">${escapeHtml(subtitle)}</div>
55	  ${desc}
56	  <div style="display:flex; gap:8px; margin-top:14px">
57	    ${hevyButton}
58	    <a href="/routine/${escapeAttr(routine.id)}" class="btn btn-ghost">Details</a>
59	  </div>
60	</div>`;
61	}
62	
63	// ──────────────────────────────────────────────────────────────────
64	// Workout data helpers
65	// ──────────────────────────────────────────────────────────────────
66	
67	/**
68	 * Format a single set as a compact string, e.g. "50kg × 8", "45 sec", "8 reps".
69	 */
70	function formatSet(set: ActualSet): string {
71	  if (set.duration_seconds != null) {
72	    const secs = set.duration_seconds;
73	    if (secs >= 60 && secs % 60 === 0) {
74	      return `${secs / 60} min`;
75	    }
76	    return `${secs} sec`;
77	  }
78	  if (set.weight_kg != null && set.weight_kg > 0 && set.reps != null) {
79	    return `${set.weight_kg}kg \u00d7 ${set.reps}`;
80	  }
81	  if (set.reps != null) {
82	    return `${set.reps} reps`;
83	  }
84	  return "1 set";
85	}
86	
87	/**
88	 * Render one exercise's sets as a compact inline string.
89	 * e.g. "45kg × 8, 50kg × 6, 50kg × 5"
90	 */
91	function formatSetsInline(sets: ActualSet[]): string {
92	  if (sets.length === 0) return "";
93	  return sets.map(formatSet).join(", ");
94	}
95	
96	/**
97	 * Parse hevy_workout_data JSON, returning an empty array on failure.
98	 */
99	function parseWorkoutData(raw: string | null): HevyWorkoutExercise[] {
100	  if (!raw) return [];
101	  try {
102	    return JSON.parse(raw) as HevyWorkoutExercise[];
103	  } catch {
104	    return [];
105	  }
106	}
107	
108	/**
109	 * Render the workout detail block for a completed item.
110	 * Returns an empty string if there is no stored workout data.
111	 */
112	function workoutDetailBlock(hevy_workout_data: string | null): string {
113	  const exercises = parseWorkoutData(hevy_workout_data);
114	  if (exercises.length === 0) return "";
115	
116	  const totalSets = exercises.reduce((sum, e) => sum + e.sets.length, 0);
117	  const summary = `${exercises.length} exercise${exercises.length !== 1 ? "s" : ""}, ${totalSets} set${totalSets !== 1 ? "s" : ""}`;
118	
119	  const exerciseRows = exercises
120	    .map((ex) => {
121	      const setsLine = formatSetsInline(ex.sets);
122	      return `<div class="workout-exercise">
123	  <span class="workout-ex-name">${escapeHtml(ex.title)}</span>
124	  ${setsLine ? `<span class="workout-ex-sets">${escapeHtml(setsLine)}</span>` : ""}
125	</div>`;
126	    })
127	    .join("\n");
128	
129	  return `<details class="workout-details">
130	  <summary class="workout-summary">${escapeHtml(summary)}</summary>
131	  <div class="workout-exercises">
132	${exerciseRows}
133	  </div>
134	</details>`;
135	}
136	
137	// ──────────────────────────────────────────────────────────────────
138	// Completed section
139	// ──────────────────────────────────────────────────────────────────
140	
141	export interface CompletedItemData {
142	  title: string;
143	  hevy_workout_data: string | null;
144	}
145	
146	/**
147	 * Completed section — items finished earlier today.
148	 * Shown with strikethrough text, a green checkmark, and expandable workout details.
149	 */
150	export function completedSection(items: CompletedItemData[]): string {
151	  if (items.length === 0) return "";
152	
153	  const rows = items
154	    .map((item) => {
155	      const detail = workoutDetailBlock(item.hevy_workout_data);
156	      return `<div class="completed-item">
157	  <div class="completed-header">
158	    <span class="completed-title">${escapeHtml(item.title)}</span>
159	    <span class="completed-check">&#10003;</span>
160	  </div>
161	  ${detail}
162	</div>`;
163	    })
164	    .join("\n");
165	
166	  return `<div class="section-header">Completed Today</div>
167	<div class="card">
168	${rows}
169	</div>`;
170	}
171	
172	/**
173	 * Upcoming section — next sessions in queue with colored dots and spacers.
174	 */
175	/**
